real_t s291(struct args_t * func_args)
{

//    loop peeling
//    wrap around variable, 1 level

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    int im1;
    for (int nl = 0; nl < 2*iterations; nl++) {
        // Peel the first iteration to handle the wrap-around case (im1 = LEN_1D-1)
        // This sets up the state for the vectorizable loop
        im1 = LEN_1D - 1;
        a[0] = (b[0] + b[im1]) * (real_t).5;

        // Main loop: regular dependency pattern a[i] = (b[i] + b[i-1]) * 0.5
        // No loop-carried dependencies on 'a' or 'b' writes, only on read indices.
        // This structure is friendly to auto-vectorization.
        #pragma clang loop vectorize(enable)
        for (int i = 1; i < LEN_1D; i++) {
            a[i] = (b[i] + b[i-1]) * (real_t).5;
        }

        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s292(struct args_t * func_args)
{

//    loop peeling
//    wrap around variable, 2 levels
//    similar to S291

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    int im1, im2;
    for (int nl = 0; nl < iterations; nl++) {
        im1 = LEN_1D-1;
        im2 = LEN_1D-2;

        // Peeling the first two iterations to resolve loop-carried dependencies
        // Iteration i = 0
        a[0] = (b[0] + b[im1] + b[im2]) * (real_t).333;
        im2 = im1;
        im1 = 0;

        // Iteration i = 1
        a[1] = (b[1] + b[im1] + b[im2]) * (real_t).333;
        im2 = im1;
        im1 = 1;

        // Main loop: dependencies are resolved, im1=i-1, im2=i-2
        // Vectorizable
        for (int i = 2; i < LEN_1D; i++) {
            a[i] = (b[i] + b[i-1] + b[i-2]) * (real_t).333;
        }

        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}
